{"content": "<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>AI 资讯快报生成器</title>
    <script src="https://cdn.jsdelivr.net/npm/html2canvas@1.4.1/dist/html2canvas.min.js"></script>
    <link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700;800&display=swap" rel="stylesheet">
    <style>
        /* =========================================
           Design Tokens - CL4R1T4S Anti-Slop
           ========================================= */
        :root {
            --bg-body: #f8fafc;
            --bg-card: #ffffff;
            --border: #e2e8f0;
            --border-hover: #cbd5e1;
            --text-tertiary: #94a3b8;
            --font-main: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, sans-serif;
            --radius-sm: 4px;
            --radius-md: 8px;
            --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.05);
        }

        /* THEME 1: Indigo */
        [data-theme="indigo"] {
            --primary: #4f46e5;
            --primary-light: #eef2ff;
            --primary-text: #3730a3;
            --text-primary: #0f172a;
            --text-secondary: #475569;
            --preview-bg: #ffffff;
            --item-bg: #ffffff;
            --preview-text: #0f172a;
            --preview-content-text: #475569;
        }

        /* THEME 2: Emerald */
        [data-theme="emerald"] {
            --primary: #059669;
            --primary-light: #ecfdf5;
            --primary-text: #065f46;
            --text-primary: #064e3b;
            --text-secondary: #047857;
            --preview-bg: #ffffff;
            --item-bg: #f0fdf4;
            --preview-text: #064e3b;
            --preview-content-text: #065f46;
        }

        /* THEME 3: Slate (Dark) */
        [data-theme="slate"] {
            --primary: #38bdf8;
            --primary-light: #0c4a6e;
            --primary-text: #7dd3fc;
            --text-primary: #f1f5f9;
            --text-secondary: #94a3b8;
            --preview-bg: #0f172a;
            --item-bg: #1e293b;
            --preview-text: #f8fafc;
            --preview-content-text: #cbd5e1;
            --border: #334155;
            --bg-body: #0f172a;
            --bg-card: #1e293b;
            --border-hover: #475569;
        }

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
            font-family: var(--font-main);
            background: var(--bg-body);
            color: var(--text-primary);
            line-height: 1.6;
            -webkit-font-smoothing: antialiased;
        }

        /* Header */
        .header {
            background: var(--bg-card);
            border-bottom: 1px solid var(--border);
            padding: 16px 24px;
            position: sticky; top: 0; z-index: 100;
        }
        .header-content { max-width: 1400px; margin: 0 auto; display: flex; align-items: center; justify-content: space-between; }
        .header-title { font-size: 18px; font-weight: 700; display: flex; align-items: center; gap: 10px; }
        .logo { width: 28px; height: 28px; background: var(--primary); border-radius: var(--radius-sm); display: flex; align-items: center; justify-content: center; }
        .logo svg { width: 16px; height: 16px; color: #fff; }

        .header-actions { display: flex; gap: 12px; align-items: center; }
        .header-btn { 
            padding: 8px 14px; border-radius: var(--radius-md); font-size: 13px; font-weight: 500; 
            cursor: pointer; border: 1px solid var(--border); background: var(--bg-card); color: var(--text-secondary); 
            display: flex; align-items: center; gap: 6px; transition: all 0.2s;
        }
        .header-btn:hover { border-color: var(--primary); color: var(--primary); }
        .header-btn.primary { background: var(--primary); color: #fff; border-color: var(--primary); }
        .header-btn.primary:hover { opacity: 0.9; color: #fff; }
        .header-btn svg { width: 14px; height: 14px; }

        /* Main Layout */
        .main { max-width: 1400px; margin: 0 auto; padding: 24px; display: grid; grid-template-columns: 1fr 1fr; gap: 24px; }
        @media (max-width: 1200px) { .main { grid-template-columns: 1fr; } }

        /* Cards */
        .card { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-md); overflow: hidden; }
        .card-header { padding: 16px 20px; border-bottom: 1px solid var(--border); display: flex; align-items: center; justify-content: space-between; }
        .card-title { font-size: 15px; font-weight: 600; display: flex; align-items: center; gap: 8px; }
        .card-body { padding: 20px; }

        /* Form */
        .form-group { margin-bottom: 20px; }
        .form-label { display: block; font-size: 13px; font-weight: 500; color: var(--text-secondary); margin-bottom: 8px; }
        .form-input { width: 100%; padding: 10px 14px; border: 1px solid var(--border); border-radius: var(--radius-md); font-size: 14px; font-family: var(--font-main); background: var(--bg-body); }
        .form-input:focus { outline: none; border-color: var(--primary); }
        .paste-textarea { width: 100%; padding: 14px; border: 1px solid var(--border); border-radius: var(--radius-md); font-size: 14px; font-family: var(--font-main); min-height: 200px; resize: vertical; background: var(--bg-body); line-height: 1.7; }
        .paste-textarea:focus { outline: none; border-color: var(--primary); }
        .btn-group { display: flex; gap: 8px; margin-top: 12px; }
        .btn { padding: 8px 14px; border-radius: var(--radius-md); font-size: 13px; font-weight: 500; cursor: pointer; border: 1px solid var(--border); background: var(--bg-card); color: var(--text-secondary); display: flex; align-items: center; gap: 6px; }
        .btn svg { width: 14px; height: 14px; }

        /* News List */
        .news-list { max-height: 240px; overflow-y: auto; border: 1px solid var(--border); border-radius: var(--radius-md); }
        .news-list-item { padding: 12px 16px; border-bottom: 1px solid var(--border); }
        .news-list-item:last-child { border-bottom: none; }
        .news-list-item .num { display: inline-block; background: var(--primary); color: #fff; font-size: 11px; font-weight: 600; padding: 2px 6px; border-radius: var(--radius-sm); margin-right: 8px; }
        .news-list-item .title { font-size: 13px; font-weight: 500; }
        .news-list-item .source { font-size: 12px; color: var(--text-tertiary); margin-top: 4px; }
        .news-list-header { display: flex; justify-content: space-between; margin-bottom: 12px; }
        .news-list-title { font-size: 13px; font-weight: 500; color: var(--text-secondary); }
        .news-count { background: var(--primary-light); color: var(--primary-text); font-size: 12px; font-weight: 600; padding: 2px 8px; border-radius: var(--radius-sm); }

        /* Preview Panel */
        .preview-panel { position: sticky; top: 80px; }
        .preview-controls { display: flex; align-items: center; justify-content: center; gap: 12px; margin-bottom: 16px; }
        .preview-nav-btn { width: 36px; height: 36px; border-radius: var(--radius-md); border: 1px solid var(--border); background: var(--bg-card); cursor: pointer; display: flex; align-items: center; justify-content: center; }
        .preview-nav-btn:disabled { opacity: 0.3; cursor: not-allowed; }
        .page-indicator { font-size: 13px; font-weight: 500; min-width: 80px; text-align: center; }
        .preview-label { font-size: 12px; color: var(--text-tertiary); background: var(--bg-body); padding: 4px 12px; border-radius: var(--radius-md); margin-bottom: 12px; text-align: center; }

        /* THE GENERATED CARD */
        #preview-container {
            background: var(--bg-body);
            width: 540px;
            height: 720px;
            box-shadow: var(--shadow-lg);
            border-radius: var(--radius-md);
            overflow: hidden;
            border: 1px solid var(--border);
        }

        #preview-content {
            background: var(--preview-bg);
            padding: 32px;
            width: 540px;
            height: 720px;
            box-sizing: border-box;
            display: flex;
            flex-direction: column;
            font-family: var(--font-main);
        }

        .preview-header {
            margin-bottom: 24px;
            padding-bottom: 16px;
            border-bottom: 2px solid var(--border);
            flex-shrink: 0;
        }

        .preview-title {
            font-size: 28px;
            font-weight: 800;
            color: var(--preview-text);
            margin-bottom: 10px;
            letter-spacing: -0.02em;
            line-height: 1.2;
        }

        .preview-meta { display: flex; align-items: center; gap: 12px; }
        .preview-date {
            font-size: 14px; font-weight: 700;
            color: var(--primary-text);
            background: var(--primary-light);
            padding: 4px 10px; border-radius: var(--radius-sm);
        }
        .preview-source-tag { font-size: 12px; color: var(--text-tertiary); font-weight: 500; }

        .preview-news-list {
            flex-grow: 1;
            display: flex;
            flex-direction: column;
            gap: 16px;
            /* 默认靠上，如果是单条模式，JS 会处理或者 CSS 处理 */
        }

        /* 单条模式居中优化 */
        .preview-news-list.single-mode {
            justify-content: center;
        }

        .preview-news-item {
            background: var(--item-bg);
            border: 1px solid var(--border);
            border-radius: var(--radius-md);
            padding: 24px; /* 增加内边距，让单条看起来更大气 */
            flex-shrink: 0;
            display: flex;
            flex-direction: column;
            justify-content: center;
        }

        /* 如果是单条模式，卡片可以更大一点 */
        .preview-news-list.single-mode .preview-news-item {
            padding: 32px;
            box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.05);
        }

        .preview-news-number {
            display: inline-block;
            align-self: flex-start;
            background: var(--primary);
            color: #fff;
            font-size: 12px; font-weight: 700;
            padding: 2px 8px; border-radius: var(--radius-sm);
            margin-bottom: 12px;
        }

        .preview-news-title {
            font-size: 18px; /* 单条时字体稍大 */
            font-weight: 700;
            color: var(--preview-text);
            margin-bottom: 12px; line-height: 1.4;
        }

        /* 多条模式字体稍小 */
        .preview-news-list:not(.single-mode) .preview-news-title {
            font-size: 16px;
        }

        .preview-news-content {
            font-size: 14px;
            color: var(--preview-content-text);
            line-height: 1.6;
            margin-bottom: 12px;
        }

        .preview-news-list:not(.single-mode) .preview-news-content {
            font-size: 13px;
        }

        .preview-news-source {
            font-size: 12px;
            color: var(--text-tertiary);
            font-weight: 600;
            border-top: 1px solid var(--border);
            padding-top: 12px;
            margin-top: auto;
        }
    </style>
</head>
<body>
    <!-- Header -->
    <header class="header">
        <div class="header-content">
            <div class="header-title">
                <div class="logo"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 2L2 7l10 5 10-5-10-5Z"/><path d="M2 17l10 5 10-5"/><path d="M2 12l10 5 10-5"/></svg></div>
                AI 资讯快报生成器
            </div>
            <div class="header-actions">
                <!-- 新增：切换风格按钮 -->
                <button class="header-btn" id="themeBtn" onclick="toggleTheme()">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M12 2a14.5 14.5 0 0 0 0 20 14.5 14.5 0 0 0 0-20"/><path d="M2 12h20"/></svg>
                    切换风格 (靛蓝)
                </button>
                <!-- 新增：切换密度按钮 (默认 1 条) -->
                <button class="header-btn" id="layoutBtn" onclick="toggleLayout()">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>
                    密度 (1 条/页)
                </button>
                <button class="header-btn" onclick="clearAll()">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/></svg> 清空
                </button>
                <button class="header-btn primary" onclick="downloadAll()">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> 下载全部
                </button>
            </div>
        </div>
    </header>

    <!-- Main Content -->
    <main class="main">
        <!-- Left Panel -->
        <div class="card">
            <div class="card-header">
                <div class="card-title">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
                    编辑内容
                </div>
            </div>
            <div class="card-body">
                <div class="form-group">
                    <label class="form-label">主标题</label>
                    <input type="text" class="form-input" id="mainTitle" value="AI 资讯快报" oninput="updatePreview()">
                </div>
                <div class="form-group">
                    <label class="form-label">日期</label>
                    <input type="text" class="form-input" id="newsDate" value="2026.04.25" oninput="updatePreview()">
                </div>
                <div class="form-group">
                    <label class="form-label">粘贴正文</label>
                    <textarea class="paste-textarea" id="pasteContent" oninput="autoParse()" placeholder="粘贴资讯正文..."></textarea>
                    <div class="btn-group">
                        <button class="btn" onclick="clearPaste()">
                            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/></svg> 清空
                        </button>
                        <button class="btn" onclick="manualParse()">
                            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 2v6h-6"/><path d="M3 12a9 9 0 0 1 15-6.7L21 8"/><path d="M3 22v-6h6"/><path d="M21 12a9 9 0 0 1-15 6.7L3 16"/></svg> 重新解析
                        </button>
                    </div>
                </div>
                <div class="news-list-container">
                    <div class="news-list-header">
                        <span class="news-list-title">已解析资讯</span>
                        <span class="news-count" id="newsCount">0</span>
                    </div>
                    <div class="news-list" id="newsList">
                        <div class="news-list-empty" style="padding:20px; text-align:center; color:#94a3b8; font-size:13px;">暂无内容</div>
                    </div>
                </div>
            </div>
        </div>

        <!-- Right Panel: Preview -->
        <div class="card preview-panel">
            <div class="card-header">
                <div class="card-title">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>
                    预览效果
                </div>
                <div style="font-size:12px; color:var(--text-tertiary); font-weight:600;" id="current-theme-label">Loading...</div>
            </div>
            <div class="card-body">
                <div class="preview-label">实时预览（540 x 720）</div>
                <div class="preview-controls">
                    <button class="preview-nav-btn" id="prevBtn" onclick="prevPage()" disabled>
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="15 18 9 12 15 6"/></svg>
                    </button>
                    <span class="page-indicator" id="pageIndicator">第 1 / 1 页</span>
                    <button class="preview-nav-btn" id="nextBtn" onclick="nextPage()" disabled>
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="9 18 15 12 9 6"/></svg>
                    </button>
                </div>
                <div style="position:relative;">
                    <div id="preview-container">
                        <div id="preview-content">
                            <!-- Dynamic Content -->
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </main>

    <script>
        let allNews = [];
        let currentPage = 0;
        let itemsPerPage = 1; // 默认改为 1 条/页 (海报模式)
        let currentThemeIndex = 0;
        const themes = ['indigo', 'emerald', 'slate'];
        const themeNames = {'indigo': '靛蓝', 'emerald': '翡翠', 'slate': '极夜'};

        // 切换风格逻辑
        function toggleTheme() {
            currentThemeIndex = (currentThemeIndex + 1) % themes.length;
            const theme = themes[currentThemeIndex];
            document.documentElement.setAttribute('data-theme', theme);
            document.getElementById('themeBtn').innerHTML = `
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M12 2a14.5 14.5 0 0 0 0 20 14.5 14.5 0 0 0 0-20"/><path d="M2 12h20"/></svg>
                切换风格 (${themeNames[theme]})
            `;
            document.getElementById('current-theme-label').textContent = `Theme: ${theme}`;
        }

        // 切换密度逻辑
        function toggleLayout() {
            itemsPerPage = itemsPerPage === 3 ? 1 : 3;
            // 更新按钮文字
            const text = itemsPerPage === 1 ? '密度 (1 条/页)' : '密度 (3 条/页)';
            document.getElementById('layoutBtn').innerHTML = `
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>
                ${text}
            `;
            currentPage = 0; // 重置页码
            updatePreview();
        }

        // 解析逻辑
        function autoParse() {
            const content = document.getElementById('pasteContent').value.trim();
            if (!content) { allNews = []; updatePreview(); return; }
            parseContent(content);
        }

        function parseContent(text) {
            const news = [];
            // 支持按空行或数字序号分割
            const blocks = text.split(/\n\s*\n|\n(?=\d+[\u3001.、])/);
            blocks.forEach(block => {
                block = block.trim(); if (!block) return;
                const lines = block.split('\n').filter(l => l.trim());
                if (lines.length < 2) return;
                const titleLine = lines[0].replace(/^\d+[\u3001.、]\s*/, '');
                const sourceLine = lines.find(l => l.startsWith('来源'));
                const contentLines = lines.filter(l => !l.startsWith('来源') && l !== lines[0]);
                if (titleLine && contentLines.length > 0) {
                    news.push({ title: titleLine.trim(), content: contentLines.join(' ').trim(), source: sourceLine ? sourceLine.replace('来源：', '').trim() : '未知' });
                }
            });
            allNews = news; currentPage = 0; updateNewsList(); updatePreview();
        }

        function updateNewsList() {
            const listEl = document.getElementById('newsList');
            const countEl = document.getElementById('newsCount');
            countEl.textContent = allNews.length;
            if (allNews.length === 0) {
                listEl.innerHTML = '<div style="padding:20px; text-align:center; color:#94a3b8; font-size:13px;">暂无内容</div>'; return;
            }
            listEl.innerHTML = allNews.map((item, i) => `
                <div class="news-list-item">
                    <span class="num">${i + 1}</span>
                    <span class="title">${item.title}</span>
                    <div class="source">来源：${item.source}</div>
                </div>
            `).join('');
        }

        function updatePreview() {
            const contentEl = document.getElementById('preview-content');
            const listContainer = contentEl.querySelector('.preview-news-list');
            const title = document.getElementById('mainTitle').value;
            const date = document.getElementById('newsDate').value;

            if (allNews.length === 0) {
                contentEl.innerHTML = `<div style="display:flex; flex-direction:column; align-items:center; justify-content:center; height:100%; color:var(--text-tertiary);"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" width="48" height="48"><path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z"/><polyline points="14 2 14 8 20 8"/></svg><div style="margin-top:16px; font-size:15px;">暂无预览内容</div></div>`;
                updatePageControls(1); return;
            }

            const totalPages = Math.ceil(allNews.length / itemsPerPage);
            const start = currentPage * itemsPerPage;
            const pageNews = allNews.slice(start, start + itemsPerPage);

            // 单条模式添加 class 用于居中
            const singleModeClass = itemsPerPage === 1 ? 'single-mode' : '';

            let newsHtml = pageNews.map((item, i) => `
                <div class="preview-news-item">
                    <div class="preview-news-number">${start + i + 1}</div>
                    <div class="preview-news-title">${item.title}</div>
                    <div class="preview-news-content">${item.content}</div>
                    <div class="preview-news-source">来源：${item.source}</div>
                </div>
            `).join('');

            contentEl.innerHTML = `
                <div class="preview-header">
                    <div class="preview-title">${title}</div>
                    <div class="preview-meta">
                        <span class="preview-date">${date}</span>
                        <span class="preview-source-tag">AI 每日精选</span>
                    </div>
                </div>
                <div class="preview-news-list ${singleModeClass}">${newsHtml}</div>
            `;
            updatePageControls(totalPages);
        }

        function updatePageControls(totalPages) {
            document.getElementById('pageIndicator').textContent = `第 ${currentPage + 1} / ${totalPages} 页`;
            document.getElementById('prevBtn').disabled = currentPage === 0;
            document.getElementById('nextBtn').disabled = currentPage >= totalPages - 1;
        }

        function prevPage() { if (currentPage > 0) { currentPage--; updatePreview(); } }
        function nextPage() { const totalPages = Math.ceil(allNews.length / itemsPerPage); if (currentPage < totalPages - 1) { currentPage++; updatePreview(); } }
        function clearPaste() { document.getElementById('pasteContent').value = ''; allNews = []; currentPage = 0; updateNewsList(); updatePreview(); }
        function clearAll() { clearPaste(); document.getElementById('mainTitle').value = 'AI 资讯快报'; document.getElementById('newsDate').value = new Date().toISOString().split('T')[0].replace(/-/g, '.'); }
        function manualParse() { const content = document.getElementById('pasteContent').value.trim(); if (content) parseContent(content); }

        async function downloadCurrent() {
            if (allNews.length === 0) return;
            const previewContent = document.getElementById('preview-content');
            const date = document.getElementById('newsDate').value.replace(/\./g, '');
            const pageNum = currentPage + 1;
