.preview-news-source {
    font-size: 12px;
    color: var(--text-tertiary);
    font-weight: 600;
    border-top: 1px solid var(--border);
    padding-top: 12px;
    margin-top: auto;
}

/* ===== TECH BLUE 主题专属样式 ===== */

/* 背景装饰 */
.techblue-bg {
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    overflow: hidden;
    pointer-events: none;
    z-index: 0;
}

.techblue-bg .wave-bottom {
    position: absolute;
    bottom: 0; left: 0; right: 0;
    height: 120px;
    background: linear-gradient(180deg, transparent 0%, rgba(37, 99, 235, 0.06) 100%);
    border-radius: 50% 50% 0 0 / 100% 100% 0 0;
}

.techblue-bg .geo-dots {
    position: absolute;
    top: 20px; right: 20px;
    width: 100px; height: 100px;
    opacity: 0.15;
}

.techblue-bg .geo-line {
    position: absolute;
    top: 60px; left: 40px;
    width: 60px; height: 2px;
    background: rgba(37, 99, 235, 0.1);
    transform: rotate(-15deg);
}

/* Tech Blue 头部样式 */
[data-theme="techblue"] .preview-header {
    position: relative;
    padding-bottom: 20px;
    border-bottom: none;
    z-index: 1;
}

[data-theme="techblue"] .preview-header::after {
    content: '';
    position: absolute;
    bottom: 0; left: 0; right: 0;
    height: 2px;
    background: linear-gradient(90deg, transparent 0%, rgba(37, 99, 235, 0.2) 50%, transparent 100%);
}

[data-theme="techblue"] .preview-title {
    font-size: 36px;
    font-weight: 800;
    color: var(--preview-text);
    margin-bottom: 8px;
    letter-spacing: -0.03em;
    line-height: 1.1;
}

[data-theme="techblue"] .preview-title .title-highlight {
    color: var(--primary);
}

