    font-size: 13px;
    color: #64748b;
    font-weight: 500;
    margin-bottom: 16px;
    letter-spacing: 0.02em;
}

[data-theme="techblue"] .preview-meta {
    display: flex;
    align-items: center;
    gap: 10px;
}

[data-theme="techblue"] .preview-date {
    font-size: 13px;
    font-weight: 600;
    color: #ffffff;
    background: var(--primary);
    padding: 6px 14px;
    border-radius: 8px;
}

[data-theme="techblue"] .preview-weekday {
    font-size: 13px;
    font-weight: 500;
    color: #64748b;
    background: #f1f5f9;
    padding: 6px 12px;
    border-radius: 8px;
}

/* 地球装饰 */
[data-theme="techblue"] .globe-deco {
    position: absolute;
    top: 10px;
    right: 20px;
