    width: 12px;
    height: 12px;
}

/* Tech Blue 卡片样式 */
[data-theme="techblue"] .preview-news-item {
    background: #ffffff;
    border: 1px solid rgba(37, 99, 235, 0.08);
    border-radius: 16px;
    padding: 20px;
    box-shadow: 0 2px 12px rgba(37, 99, 235, 0.06);
    position: relative;
}

[data-theme="techblue"] .preview-news-number {
    background: var(--primary);
