    color: #0f172a;
    margin-bottom: 10px;
    line-height: 1.45;
}

[data-theme="techblue"] .preview-news-content {
    font-size: 13px;
    color: #64748b;
    line-height: 1.65;
    margin-bottom: 14px;
}

[data-theme="techblue"] .preview-news-source {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 12px;
    color: #94a3b8;
    font-weight: 500;
    border-top: 1px solid #f1f5f9;
    padding-top: 12px;
    margin-top: auto;
}

[data-theme="techblue"] .preview-news-source svg {
    width: 14px;
    height: 14px;
    color: #94a3b8;
}

/* Tech Blue 新闻列表容器 */
[data-theme="techblue"] .preview-news-list {
    gap: 14px;
    position: relative;
    z-index: 1;
}

/* 水波纹底部装饰 */
[data-theme="techblue"] .water-wave {
    position: absolute;
