function updatePreview() {
    const contentEl = document.getElementById('preview-content');
    const title = document.getElementById('mainTitle').value;
    const date = document.getElementById('newsDate').value;
    const currentTheme = themes[currentThemeIndex];

    if (allNews.length === 0) {
        contentEl.innerHTML = `<div style="display:flex; flex-direction:column; align-items:center; justify-content:center; height:100%; color:var(--text-tertiary);"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" width="48" height="48"><path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z"/><polyline points="14 2 14 8 20 8"/></svg><div style="margin-top:16px; font-size:15px;">暂无预览内容</div></div>`;
        updatePageControls(1); return;
    }

    const totalPages = Math.ceil(allNews.length / itemsPerPage);
    const start = currentPage * itemsPerPage;
    const pageNews = allNews.slice(start, start + itemsPerPage);
    const singleModeClass = itemsPerPage === 1 ? 'single-mode' : '';

    // 计算星期
    let weekdayStr = '';
    if (date) {
        const d = new Date(date.replace(/\./g, '-'));
        const weekdays = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'];
        if (!isNaN(d)) weekdayStr = weekdays[d.getDay()];
    }

    let newsHtml = '';

    if (currentTheme === 'techblue') {
        // Tech Blue 主题专属 HTML 结构
        newsHtml = pageNews.map((item, i) => `
            <div class="preview-news-item">
                <div class="ai-insight-tag">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 2l2.4 7.4H22l-6.2 4.5 2.4 7.4L12 16.8l-6.2 4.5 2.4-7.4L2 9.4h7.6z"/></svg>
                    AI Insight
                </div>
                <div class="preview-news-number">${String(start + i + 1).padStart(2, '0')}</div>
                <div class="preview-news-title">${item.title}</div>
                <div class="preview-news-content">${item.content}</div>
                <div class="preview-news-source">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>
                    来源：${item.source}
                </div>
            </div>
        `).join('');

        // 处理标题：将第一个词高亮（如"全球早报"中的"早报"）
        let displayTitle = title;
        const spaceIndex = title.indexOf(' ');
        if (spaceIndex > 0) {
            displayTitle = `<span style="color:#0f172a">${title.substring(0, spaceIndex)}</span><span class="title-highlight">${title.substring(spaceIndex)}</span>`;
        }

        contentEl.innerHTML = `
            <div class="techblue-bg">
                <div class="geo-line"></div>
                <div class="wave-bottom"></div>
                <svg class="water-wave" viewBox="0 0 540 60" preserveAspectRatio="none">
                    <path d="M0 30 Q67.5 10 135 30 T270 30 T405 30 T540 30 V60 H0 Z" fill="rgba(37,99,235,0.06)"/>
                    <path d="M0 35 Q67.5 20 135 35 T270 35 T405 35 T540 35 V60 H0 Z" fill="rgba(37,99,235,0.04)"/>
                </svg>
            </div>
            <div class="preview-header">
                <div class="preview-title">${displayTitle}</div>
                <div class="preview-subtitle">AI 每日精选 · 洞见科技未来</div>
                <div class="preview-meta">
                    <span class="preview-date">${date}</span>
                    ${weekdayStr ? `<span class="preview-weekday">${weekdayStr}</span>` : ''}
                </div>
                <svg class="globe-deco" viewBox="0 0 120 120" fill="none">
                    <circle cx="60" cy="60" r="45" stroke="rgba(37,99,235,0.15)" stroke-width="2"/>
                    <ellipse cx="60" cy="60" rx="45" ry="20" stroke="rgba(37,99,235,0.1)" stroke-width="1.5"/>
                    <ellipse cx="60" cy="60" rx="20" ry="45" stroke="rgba(37,99,235,0.1)" stroke-width="1.5"/>
                    <circle cx="60" cy="60" r="45" fill="url(#globeGrad)" opacity="0.3"/>
                    <defs><linearGradient id="globeGrad" x1="0" y1="0" x2="1" y2="1"><stop offset="0%" stop-color="#3b82f6"/><stop offset="100%" stop-color="#1d4ed8"/></linearGradient></defs>
                </svg>
            </div>
            <div class="preview-news-list ${singleModeClass}">${newsHtml}</div>
        `;
    } else {
        // 其他主题的默认 HTML
        newsHtml = pageNews.map((item, i) => `
            <div class="preview-news-item">
                <div class="preview-news-number">${start + i + 1}</div>
                <div class="preview-news-title">${item.title}</div>
                <div class="preview-news-content">${item.content}</div>
                <div class="preview-news-source">来源：${item.source}</div>
            </div>
        `).join('');

        contentEl.innerHTML = `
            <div class="preview-header">
                <div class="preview-title">${title}</div>
                <div class="preview-meta">
                    <span class="preview-date">${date}</span>
                    <span class="preview-source-tag">AI 每日精选</span>
                </div>
            </div>
            <div class="preview-news-list ${singleModeClass}">${newsHtml}</div>
        `;
    }
    updatePageControls(totalPages);
}

