{"content": "<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>AI 资讯快报生成器 (Tech Blue)</title>
    <script src="https://cdn.jsdelivr.net/npm/html2canvas@1.4.1/dist/html2canvas.min.js"></script>
    <link href="https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap" rel="stylesheet">
    <style>
        /* =========================================
           核心设计规范 - 严格对齐设计稿
           ========================================= */
        :root {
            --bg-body: #f8fafc;
            --bg-card: #ffffff;
            --border: #e2e8f0;
            --border-hover: #cbd5e1;
            --text-tertiary: #94a3b8;
            --font-main: 'Noto Sans SC', -apple-system, BlinkMacSystemFont, sans-serif;
            --radius-sm: 6px;
            --radius-md: 12px;
            --radius-lg: 24px; /* 卡片大圆角 */
            --shadow-card: 0 4px 20px rgba(37, 99, 235, 0.06);
        }

        /* 设计稿色彩系统 */
        .theme-design {
            --primary: #2563eb;
            --primary-dark: #1d4ed8;
            --primary-light: #eff6ff;
            --text-primary: #0f172a;
            --text-secondary: #475569;
            --text-subtitle: #64748b;
            --card-bg: #ffffff;
            --bg-gradient: linear-gradient(180deg, #f8fbff 0%, #eef5ff 100%);
        }

        /* UI 界面样式 (不导出) */
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: var(--font-main); background: var(--bg-body); color: var(--text-primary); line-height: 1.6; }

        /* Header 工具栏 */
        .header { background: #fff; border-bottom: 1px solid var(--border); padding: 12px 24px; position: sticky; top: 0; z-index: 100; }
        .header-content { max-width: 1400px; margin: 0 auto; display: flex; align-items: center; justify-content: space-between; }
        .header-title { font-size: 18px; font-weight: 700; display: flex; align-items: center; gap: 8px; }
        .header-actions { display: flex; gap: 8px; }
        .header-btn { padding: 6px 12px; border-radius: 6px; font-size: 13px; cursor: pointer; border: 1px solid var(--border); background: #fff; display: flex; align-items: center; gap: 4px; }
        .header-btn.primary { background: var(--primary); color: #fff; border-color: var(--primary); }

        /* 主布局 */
        .main { max-width: 1400px; margin: 0 auto; padding: 20px; display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
        @media (max-width: 1200px) { .main { grid-template-columns: 1fr; } }

        /* 左侧面板 */
        .card { background: #fff; border: 1px solid var(--border); border-radius: 12px; overflow: hidden; }
        .card-header { padding: 16px 20px; border-bottom: 1px solid var(--border); font-weight: 600; font-size: 15px; }
        .card-body { padding: 20px; }
        .form-group { margin-bottom: 16px; }
        .form-label { display: block; font-size: 13px; font-weight: 500; color: var(--text-secondary); margin-bottom: 6px; }
        .form-input, .paste-textarea { width: 100%; padding: 10px; border: 1px solid var(--border); border-radius: 8px; font-family: var(--font-main); font-size: 14px; }
        .paste-textarea { min-height: 180px; resize: vertical; }
        .news-list { max-height: 200px; overflow-y: auto; border: 1px solid var(--border); border-radius: 8px; }
        .news-list-item { padding: 10px 14px; border-bottom: 1px solid var(--border); font-size: 13px; }
        .news-list-item:last-child { border-bottom: none; }
        .news-count { font-size: 12px; background: var(--primary-light); color: var(--primary); padding: 2px 8px; border-radius: 10px; font-weight: 600; }

        /* 右侧预览区 */
        .preview-panel { position: sticky; top: 80px; }
        .preview-label { text-align: center; font-size: 12px; color: #94a3b8; margin-bottom: 8px; }
        .preview-controls { display: flex; justify-content: center; gap: 12px; margin-bottom: 12px; }
        .nav-btn { width: 32px; height: 32px; border-radius: 6px; border: 1px solid var(--border); background: #fff; cursor: pointer; display: flex; align-items: center; justify-content: center; }
        .nav-btn:disabled { opacity: 0.3; cursor: not-allowed; }

        /* =========================================
           🎨 导出区域样式 (Pixel-Perfect 还原)
           ========================================= */
        #preview-container {
            background: #fff;
            width: 540px;
            height: 720px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.1);
            border-radius: 8px;
            overflow: hidden;
            margin: 0 auto;
        }

        #preview-content {
            width: 540px;
            height: 720px;
            padding: 28px 24px;
            box-sizing: border-box;
            font-family: var(--font-main);
            background: var(--bg-gradient);
            position: relative;
            overflow: hidden;
            display: flex;
            flex-direction: column;
        }

        /* 背景装饰 (还原设计稿) */
        .bg-deco { position: absolute; top: 0; left: 0; width: 100%; height: 100%; pointer-events: none; z-index: 0; }
        .bg-deco .circuit-line {
            position: absolute; top: 40px; left: 0; width: 200px; height: 60px;
            background: url("data:image/svg+xml,%3Csvg width='200' height='60' viewBox='0 0 200 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M0 30 L50 30 L70 10 L120 10 L140 30 L200 30' stroke='%2393c5fd' stroke-width='1.5' fill='none' stroke-dasharray='4 4' opacity='0.3'/%3E%3Ccircle cx='70' cy='10' r='3' fill='%2393c5fd' opacity='0.3'/%3E%3Ccircle cx='140' cy='30' r='3' fill='%2393c5fd' opacity='0.3'/%3E%3C/svg%3E") no-repeat;
            opacity: 0.6;
        }
        .bg-deco .globe {
            position: absolute; top: -10px; right: -10px; width: 220px; height: 220px;
            background: url("data:image/svg+xml,%3Csvg width='220' height='220' viewBox='0 0 220 220' xmlns='http://www.w3.org/2000/svg'%3E%3Cdefs%3E%3ClinearGradient id='g' x1='0' y1='0' x2='1' y2='1'%3E%3Cstop offset='0' stop-color='%232563eb' stop-opacity='0.1'/%3E%3Cstop offset='1' stop-color='%233b82f6' stop-opacity='0.3'/%3E%3C/linearGradient%3E%3C/defs%3E%3Ccircle cx='110' cy='110' r='80' fill='url(%23g)'/%3E%3Cellipse cx='110' cy='110' rx='80' ry='30' stroke='%232563eb' stroke-width='1.5' fill='none' opacity='0.2'/%3E%3Cellipse cx='110' cy='110' rx='30' ry='80' stroke='%232563eb' stroke-width='1.5' fill='none' opacity='0.2'/%3E%3Cpath d='M30 110 Q110 40 190 110 Q110 180 30 110' fill='%232563eb' opacity='0.05'/%3E%3C/svg%3E") no-repeat center;
            background-size: contain;
            opacity: 0.8;
        }
        .bg-deco .wave {
            position: absolute; bottom: 0; left: 0; width: 100%; height: 100px;
            background: url("data:image/svg+xml,%3Csvg width='540' height='100' viewBox='0 0 540 100' preserveAspectRatio='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M0 50 Q135 20 270 50 T540 50 V100 H0 Z' fill='%232563eb' opacity='0.05'/%3E%3Cpath d='M0 60 Q135 40 270 60 T540 60 V100 H0 Z' fill='%233b82f6' opacity='0.08'/%3E%3C/svg%3E") no-repeat bottom;
            background-size: cover;
        }

        /* 头部排版 */
        .p-header { position: relative; z-index: 1; margin-bottom: 20px; }
        .p-title-row { display: flex; align-items: baseline; margin-bottom: 6px; }
        .p-title { font-size: 36px; font-weight: 900; line-height: 1.2; color: var(--text-primary); letter-spacing: -1px; }
        .p-title .hl { color: var(--primary); }
        .p-subtitle { font-size: 13px; color: var(--text-subtitle); font-weight: 500; letter-spacing: 1px; margin-bottom: 12px; }

        .p-tags { display: flex; gap: 10px; }
        .p-tag { padding: 5px 12px; border-radius: 6px; font-size: 13px; font-weight: 600; }
        .p-tag.date { background: var(--primary); color: #fff; }
        .p-tag.week { background: #fff; color: var(--primary); border: 1px solid rgba(37, 99, 235, 0.2); }

        /* 卡片列表 */
        .p-list { flex: 1; display: flex; flex-direction: column; gap: 14px; position: relative; z-index: 1; }
        .p-list.single-mode { justify-content: center; }

        .p-card {
            background: var(--card-bg);
            border-radius: var(--radius-lg);
            padding: 20px;
            box-shadow: var(--shadow-card);
            display: flex;
            flex-direction: column;
            position: relative;
            border: 1px solid rgba(255, 255, 255, 0.5);
        }

        .p-card-top { display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px; }
        .p-insight { font-size: 11px; color: var(--primary); font-weight: 600; display: flex; align-items: center; gap: 4px; }
        .p-insight svg { width: 10px; height: 10px; }

        .p-row { display: flex; gap: 14px; }
        .p-num { 
            min-width: 34px; height: 34px; 
            background: var(--primary); 
            color: #fff; 
            font-size: 15px; font-weight: 800; 
            display: flex; align-items: center; justify-content: center; 
            border-radius: 8px;
            box-shadow: 0 2px 6px rgba(37, 99, 235, 0.3);
        }

        .p-content { flex: 1; }
        .p-card-title { font-size: 16px; font-weight: 700; color: var(--text-primary); line-height: 1.4; margin-bottom: 8px; }
        .p-card-desc { font-size: 12.5px; color: var(--text-secondary); line-height: 1.6; margin-bottom: 12px; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }

        .p-footer { display: flex; align-items: center; gap: 6px; font-size: 11px; color: var(--text-tertiary); font-weight: 500; padding-top: 10px; border-top: 1px solid #f1f5f9; margin-top: auto; }
        .p-footer svg { width: 12px; height: 12px; opacity: 0.7; }
    </style>
</head>
<body>
    <!-- Header -->
    <header class="header">
        <div class="header-content">
            <div class="header-title">🎨 科技蓝生成器</div>
            <div class="header-actions">
                <button class="header-btn" onclick="toggleLayout()">
                    📐 密度 (2 条/页)
                </button>
                <button class="header-btn primary" onclick="downloadAll()">
                    ⬇️ 下载全部
                </button>
            </div>
        </div>
    </header>

    <!-- Main Content -->
    <main class="main">
        <!-- Left Panel -->
        <div class="card">
            <div class="card-header">编辑内容</div>
            <div class="card-body">
                <div class="form-group">
                    <label class="form-label">主标题</label>
                    <input type="text" class="form-input" id="mainTitle" value="全球早报" oninput="updatePreview()">
                </div>
                <div class="form-group">
                    <label class="form-label">日期 (yyyy.mm.dd)</label>
                    <input type="text" class="form-input" id="newsDate" value="2026.04.27" oninput="updatePreview()">
                </div>
                <div class="form-group">
                    <label class="form-label">粘贴正文</label>
                    <textarea class="paste-textarea" id="pasteContent" oninput="autoParse()" placeholder="粘贴资讯正文..."></textarea>
                </div>
                <div class="news-list-header" style="display:flex; justify-content:space-between; margin-bottom:8px;">
                    <span style="font-size:13px; font-weight:500; color:#475569;">已解析资讯</span>
                    <span class="news-count" id="newsCount">0</span>
                </div>
                <div class="news-list" id="newsList">
                    <div style="padding:20px; text-align:center; color:#94a3b8; font-size:13px;">暂无内容</div>
                </div>
            </div>
        </div>

        <!-- Right Panel: Preview -->
        <div class="card preview-panel">
            <div class="card-header">实时预览</div>
            <div class="card-body">
                <div class="preview-label">540 x 720</div>
                <div class="preview-controls">
                    <button class="nav-btn" id="prevBtn" onclick="prevPage()" disabled>&lt;</button>
                    <span id="pageIndicator" style="font-size:13px; font-weight:600; min-width:80px; text-align:center;">第 1 / 1 页</span>
                    <button class="nav-btn" id="nextBtn" onclick="nextPage()" disabled>&gt;</button>
                </div>
                <div id="preview-container">
                    <div id="preview-content">
                        <!-- Dynamic Content -->
                    </div>
                </div>
            </div>
        </div>
    </main>

    <script>
        let allNews = [];
        let currentPage = 0;
        let itemsPerPage = 2;

        // 解析逻辑
        function autoParse() {
            const content = document.getElementById('pasteContent').value.trim();
            if (!content) { allNews = []; updatePreview(); return; }
            parseContent(content);
        }

        function parseContent(text) {
            const news = [];
            const blocks = text.split(/\n\s*\n|\n(?=\d+[\u3001.、])/);
            blocks.forEach(block => {
                block = block.trim(); if (!block) return;
                const lines = block.split('\n').filter(l => l.trim());
                if (lines.length < 2) return;
                const titleLine = lines[0].replace(/^\d+[\u3001.、]\s*/, '');
                const sourceLine = lines.find(l => l.startsWith('来源'));
                const contentLines = lines.filter(l => !l.startsWith('来源') && l !== lines[0]);
                if (titleLine && contentLines.length > 0) {
                    news.push({ 
                        title: titleLine.trim(), 
                        content: contentLines.join(' ').trim(), 
                        source: sourceLine ? sourceLine.replace('来源：', '').trim() : '未知' 
                    });
                }
            });
            allNews = news; currentPage = 0; updateNewsList(); updatePreview();
        }

        function updateNewsList() {
            const listEl = document.getElementById('newsList');
            const countEl = document.getElementById('newsCount');
            countEl.textContent = allNews.length;
            if (allNews.length === 0) {
                listEl.innerHTML = '<div style="padding:20px; text-align:center; color:#94a3b8; font-size:13px;">暂无内容</div>'; return;
            }
            listEl.innerHTML = allNews.map((item, i) => `
                <div class="news-list-item">
                    <span style="color:#2563eb; font-weight:600; margin-right:6px;">${i + 1}</span> ${item.title}
                </div>
            `).join('');
        }

        function getWeekday(dateStr) {
            if (!dateStr) return '';
            const d = new Date(dateStr.replace(/\./g, '-'));
            const weeks = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'];
            return isNaN(d) ? '' : weeks[d.getDay()];
        }

        function updatePreview() {
            const contentEl = document.getElementById('preview-content');
            const titleInput = document.getElementById('mainTitle').value;
            const date = document.getElementById('newsDate').value;

            if (allNews.length === 0) {
                contentEl.innerHTML = `<div style="display:flex; align-items:center; justify-content:center; height:100%; color:#94a3b8;">暂无预览内容</div>`;
                updatePageControls(1); return;
            }

            const totalPages = Math.ceil(allNews.length / itemsPerPage);
            const start = currentPage * itemsPerPage;
            const pageNews = allNews.slice(start, start + itemsPerPage);
            const singleModeClass = itemsPerPage === 1 ? 'single-mode' : '';

            // 处理标题高亮 (如 "全球早报" -> "全球"普通 "早报"高亮)
            let titleHtml = titleInput;
            const words = titleInput.split(' ');
            if (words.length > 1) {
                titleHtml = `<span>${words[0]}</span><span class="hl">${words.slice(1).join(' ')}</span>`;
            }

            // 卡片生成
            let cardsHtml = pageNews.map((item, i) => `
                <div class="p-card">
                    <div class="p-card-top">
                        <div class="p-insight">
                            <svg viewBox="0 0 24 24" fill="currentColor"><path d="M12 2L14.5 9.5L22 12L14.5 14.5L12 22L9.5 14.5L2 12L9.5 9.5L12 2Z"/></svg>
                            AI Insight
                        </div>
                    </div>
                    <div class="p-row">
                        <div class="p-num">${String(start + i + 1).padStart(2, '0')}</div>
                        <div class="p-content">
                            <div class="p-card-title">${item.title}</div>
                            <div class="p-card-desc">${item.content}</div>
                            <div class="p-footer">
                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>
                                来源：${item.source}
                            </div>
                        </div>
                    </div>
                </div>
            `).join('');

            contentEl.innerHTML = `
                <div class="bg-deco">
                    <div class="circuit-line"></div>
                    <div class="globe"></div>
                    <div class="wave"></div>
                </div>
                <div class="p-header">
                    <div class="p-title-row">
                        <div class="p-title">${titleHtml}</div>
                    </div>
                    <div class="p-subtitle">AI 每日精选 · 洞见科技未来</div>
                    <div class="p-tags">
                        <span class="p-tag date">${date}</span>
                        <span class="p-tag week">${getWeekday(date)}</span>
                    </div>
                </div>
                <div class="p-list ${singleModeClass}">
                    ${cardsHtml}
                </div>
            `;
            updatePageControls(totalPages);
        }

        function updatePageControls(totalPages) {
            document.getElementById('pageIndicator').textContent = `第 ${currentPage + 1} / ${totalPages} 页`;
            document.getElementById('prevBtn').disabled = currentPage === 0;
            document.getElementById('nextBtn').disabled = currentPage >= totalPages - 1;
        }

        function prevPage() { if (currentPage > 0) { currentPage--; updatePreview(); } }
        function nextPage() { const totalPages = Math.ceil(allNews.length / itemsPerPage); if (currentPage < totalPages - 1) { currentPage++; updatePreview(); } }

        function toggleLayout() {
            itemsPerPage = itemsPerPage === 2 ? 1 : 2;
            document.querySelector('.header-btn').textContent = `📐 密度 (${itemsPerPage} 条/页)`;
            currentPage = 0; updatePreview();
        }

        async function downloadAll() {
            if (allNews.length === 0) return;
            const totalPages = Math.ceil(allNews.length / itemsPerPage);
            const date = document.getElementById('newsDate').value.replace(/\./g, '');
            const originalPage = currentPage;

            for (let i = 0; i < totalPages; i++) {
                currentPage = i; updatePreview();
                await new Promise(resolve => setTimeout(resolve, 400));

                const previewContent = document.getElementById('preview-content');
                const canvas = await html2canvas(previewContent, { scale: 2, backgroundColor: null, logging: false, useCORS: true });
                const link = document.createElement('a');
                link.download = `AI_资讯_${date}_P${i + 1}.jpg`;
                link.href = canvas.toDataURL('image/jpeg', 0.95);
                link.click();
                await new Promise(resolve => setTimeout(resolve, 600));
            }
            currentPage = originalPage; updatePreview();
            alert(`已下载 ${totalPages} 张图片`);
        }

        window.onload = function() { updatePreview(); };
    </script>
</body>
</html>
